import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormControl, Switch, FormControlLabel, Button } from '@material-ui/core';
import { subjectActions } from '../actions';
import { subjectStrings } from '../config';
import { sessionStrings, sessionActions } from '../../Sessions';
import { MyPopupMenu } from '../../../includes';
import { colors } from '../../../../utils';
import { teacherActions } from '../../Teachers';


const style = theme => ({
    root: {
        // margin: 10
    }
})
class _SubjectMainStageComponent extends Component {
    componentDidMount() {
        const {
            dispatch,
            [sessionStrings.levels] : levels
        } = this.props;
        if(!levels) sessionActions.getCurrentSessionLevel()(dispatch);
        this.editModeChangeHandler = this.editModeChangeHandler.bind(this);
    }
    
    setSubjectFilter = e => {
        const {dispatch} = this.props;
        subjectActions.setSubjectFilter(e.target.checked)(dispatch);
    }
    levelSelectHandler = selectedLevel => {
        const {dispatch} = this.props;
        subjectActions.setSelectedLevel(selectedLevel)(dispatch);
        sessionActions.getSessionTerms(selectedLevel._id)(dispatch);
        teacherActions.getLevelTeachers(selectedLevel._id)(dispatch);
    }
    termSelectHandler = selectedTerm => {
        const {dispatch} = this.props;
        subjectActions.setSelectedTerm(selectedTerm)(dispatch);
    }
    setUsePreviousSubjects = e => {
        const {dispatch} = this.props;
        subjectActions.setUsePreviousSubjects(e.target.checked)(dispatch);
    }
    editModeChangeHandler = ()=>{
        const {
            [subjectStrings.subjedTeacherEditMode] : mode,
            dispatch
        } = this.props;
        subjectActions.setSubjedTeacherEditMode(!mode)(dispatch);
    }
    render() {
        const {
            classes, 
            [subjectStrings.subjectFilter] : subjectFilter,
            [subjectStrings.selectedLevel] : selectedLevel,
            [subjectStrings.selectedTerm] : selectedTerm,
            [subjectStrings.usePreviousSubjects] : usePreviousSubjects,
            [subjectStrings.subjectCount] : subjectCount,
            [subjectStrings.subjedTeacherEditMode] : subjedTeacherEditMode,
            [sessionStrings.levels] : levels,
            [sessionStrings.terms] : terms,
        } = this.props;
        return (
            <div className={classes.root}>
                <FormControl style={{padding : 10}}>
                    <FormControlLabel
                        style={{color : colors.white}}
                        control={<Switch
                            checked={Boolean(subjectFilter)}
                            onChange={this.setSubjectFilter.bind(this)}/>}
                        label="Filter"/>
                </FormControl>
                {subjectFilter && <Fragment>
                    <FormControl>
                        <MyPopupMenu
                            buttonValue={(selectedLevel && selectedLevel.name) || "Levels"}
                            buttonName="level"
                            options={levels}
                            optionNameProp="name"
                            optionValueProp="_id"
                            optionClickCallback={this.levelSelectHandler.bind(this)}
                            />
                    </FormControl>
                    <FormControl>
                        <MyPopupMenu
                            buttonValue={(selectedTerm && selectedTerm.name) || "Terms"}
                            buttonName="terms"
                            options={terms}
                            optionNameProp="name"
                            optionValueProp="_id"
                            optionClickCallback={this.termSelectHandler.bind(this)}
                            />
                    </FormControl>
                </Fragment>}
                {subjectCount === 0 && <FormControl style={{padding : 10}}>
                    <FormControlLabel
                        style={{color : colors.white}}
                        control={<Switch
                            value={usePreviousSubjects}
                            onChange={this.setUsePreviousSubjects.bind(this)}/>}
                        label="Use previous"/>
                </FormControl>}
                {/* <div style={{display : "flex", flexGrow :1}}/> */}
                <FormControl style={{padding : 10}}>
                    <Button 
                    disabled={Boolean(!subjectFilter || !selectedLevel)}
                    style={
                        subjectFilter && selectedLevel ? ({backgroundColor : colors.secondary, color: colors.white}) :
                        ({backgroundColor : colors.grayTrans, color : colors.gray})}
                    onClick={this.editModeChangeHandler}>{
                        subjedTeacherEditMode ? "Save" : "Edit"
                    }</Button>
                </FormControl>
                <FormControl style={{padding : 10}}>
                    {subjedTeacherEditMode && 
                    <Button color="secondary" onClick={this.editModeChangeHandler}>Cancel</Button>}
                </FormControl>
            </div>
        );
    }
}


_SubjectMainStageComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({subjectReducer, sessionReducer}) => ({
    [subjectStrings.subjectFilter] : subjectReducer[subjectStrings.subjectFilter],
    [subjectStrings.selectedLevel] : subjectReducer[subjectStrings.selectedLevel],
    [subjectStrings.selectedTerm] : subjectReducer[subjectStrings.selectedTerm],
    [subjectStrings.usePreviousSubjects] : subjectReducer[subjectStrings.usePreviousSubjects],
    [subjectStrings.subjedTeacherEditMode] : subjectReducer[subjectStrings.subjedTeacherEditMode],
    [sessionStrings.levels] : sessionReducer[sessionStrings.levels],
    [sessionStrings.terms] : sessionReducer[sessionStrings.terms],
})


export const SubjectMainStageComponent = connect(mapStateToProps)(withStyles(style)(_SubjectMainStageComponent));