import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { subjectActions } from '../../../actions';

import { 
    headerActions, breadCrumbActions, 
    mainStageHeaderAction, mainStageHeaderStrings, 
    MyTable, EditableCellMapFormat, headerStrings
 } from '../../../../../includes';
import { StudentAndAssessmentsStageHeaderComponent } from './StudentAndAssessmentsStageHeaderComponent';
import { subjectStrings } from '../../../config';
import { routeNamesSchool } from '../../../../routeNames';

const style = theme => ({
    root: {
        marginTop : 40
    }
})
class _StudentAndAssessments extends Component {
    constructor(props) {
        super(props);
        this.state = {
            studentUnusable : null,
            tableData : null,
            tableDataInputTypes : null
        }
        const {dispatch} = props;
        const {_id, levelId, termId, name} = this.props.subject|| {};
        this.levelId = levelId || 1;
        this.termId = termId || 1;
        this.subjectId = _id || 1;
        this.subjectName = name || "Biology";
        subjectActions.getLevelClasses(this.levelId)(dispatch);

        headerActions({
            [headerStrings.headerTitle] : "SUBJECTS (VIEW)"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Subjects", path : routeNamesSchool.subjects}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.searchActions] : ()=>{},
            [mainStageHeaderStrings.components] :[
                ()=><StudentAndAssessmentsStageHeaderComponent
                        levelId={this.levelId}/>
            ],
            [mainStageHeaderStrings.buttons] : [
                {value : "Back", onClick : ()=>this.props.goBack()}
            ]
        })(dispatch);
    }
    
    componentDidMount() {
        const { 
            dispatch
        } = this.props;    
        subjectActions.getSubjectLevelStudents(
            this.levelId
        )(dispatch);
        subjectActions.getSubjectAssessments(
            this.levelId
        )(dispatch);
    }
    static getDerivedStateFromProps(nextProps, prevState) {
        
        if(!prevState.studentUnusable || 
            JSON.stringify(prevState.studentUnusable) !==
            JSON.stringify(nextProps[subjectStrings.subjectStudents])){
                prevState.studentUnusable = 
                    nextProps[subjectStrings.subjectStudents];
                prevState.tableData = StudentAndAssessments.generateTableData(
                    nextProps, prevState.studentUnusable
                );
                prevState = {...prevState, ...StudentAndAssessments.generateTableHeader(nextProps)}
            }
        return prevState;
    }
    
    static generateTableHeader(props){
        let header = ["Students"];
        let dataMap = ["student"];
        let tableInputTypes = {};
        const {assessments} = props[subjectStrings.subjectAssessments] || {};
        if(assessments){
            for (let i = 0; i < assessments.length; i++) {
                const assessment = assessments[i];
                header.push(assessment.name);
                dataMap.push(assessment._id);
                tableInputTypes[assessment._id] = "number"
            }
        }
        header.push("Total", "Grade", "Class. Pos", "Level Pos.", "Actions");
        dataMap.push("total", "grade", "classPosition", "levelPosition", "action");

        return {header, dataMap, tableInputTypes};
    }
    static generateTableData(props, students){
        let {_id, levelId, termId, name} = props.subject|| {};
        levelId = levelId || 1;
        termId = termId || 1;
        const subjectId = _id || 1;
        const subjectName = name || "Biology";

        let data = [];
        if(students) for (let i = 0; i < students.length; i++) {
            const { fullName, terms, studentId } = students[i];
            let cellInfo = {student : fullName, studentId};            
            if(terms){
                for (let l = 0; l < terms.length; l++) {
                    const term = terms[l];
                    if(term.termId === termId){
                        const { subjects } = term;
                        if(subjects){
                            for (let k = 0; k < subjects.length; k++) {
                                const sub = subjects[k];
                                if(sub._id === subjectId){
                                    const {assessments} = sub;               
                                    let total = 0;
                                    for (let j = 0; j < assessments.length; j++) {
                                        const assess = assessments[j];
                                        cellInfo[assess.assessmentIds] = assess.score;
                                        total +=assess.score;
                                    }
                                    cellInfo.total = total;
                                }
                            }
                        }
                    }
                }
            }
            cellInfo.editable = true;
            data.push(cellInfo);
        }
        return data;
    }
    cellMapFormat = (superProps)=>props=><EditableCellMapFormat {...props} {...superProps}/>
    editBtnHandler= (student)=>()=>{
        const { tableData } = this.state;
        student.editing = true;
        const {item, index} = 
        tableData.
                getFirstObjectByPropValue("studentId", student.studentId) || {};
        if(item){
            tableData[index] = student;
            const newStudents = [...tableData];
            this.setState({tableData: newStudents});
        }
        
    }
    cancelEditBtnHandler = student => () =>{
        const {
            tableData
        } = this.state;
        delete student.editing;
        delete student.context;
        const {item, index} = 
            tableData.
                getFirstObjectByPropValue("studentId", student.studentId) || {};
        if(item){
            tableData[index] = student;
            const newStudents = [...tableData];
            this.setState({tableData: newStudents});
        }
    }
    editFinishBtnHandler = student => () => {
        const {context} = student;
        const {assessments} = this.props[subjectStrings.subjectAssessments] || {};
        if(assessments){
            let total = 0;
            for (let i = 0; i < assessments.length; i++) {
                const assessment = assessments[i];
                if(context[assessment._id]){
                    student[assessment._id] = context[assessment._id].state.data.value;
                    if(student[assessment._id])
                        total += parseInt(student[assessment._id]);
                }
            }
            student.total = total;
        }
        delete student.context;
        const {
            tableData
        } = this.state;
        delete student.editing;
        const {item, index} = 
            tableData.
                getFirstObjectByPropValue("studentId", student.studentId) || {};
        if(item){
            tableData[index] = student;
            const newStudents = [...tableData];
            this.setState({tableData: newStudents});
            /**
             * TO DO
             * save in database
             */
        }

    }
    render() {
        const {classes} = this.props;
        const {tableData, header, dataMap, tableInputTypes} = this.state;
        return (
            <div className={classes.root}>
                <MyTable
                    title={this.subjectName}
                    header={header}
                    dataMap={dataMap}
                    data={tableData}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["student", "total", "grade", "levelPosition", "classPosition"],
                        editBtnHandler : this.editBtnHandler.bind(this),
                        cancelEditBtnHandler : this.cancelEditBtnHandler.bind(this),
                        editFinishBtnHandler : this.editFinishBtnHandler.bind(this),
                        inputTypeMap : tableInputTypes
                    })}
                    />
            </div>
        );
    }
}


_StudentAndAssessments.propTypes = {
    classes : PropTypes.object.isRequired,
    goBack : PropTypes.func,
    subject : PropTypes.object,
};
const mapStateToProps = ({subjectReducer}) => ({
    [subjectStrings.subjectAssessments] : subjectReducer[subjectStrings.subjectAssessments],
    [subjectStrings.subjectStudents] : subjectReducer[subjectStrings.subjectStudents],
})


export const StudentAndAssessments = connect(mapStateToProps)(withStyles(style)(_StudentAndAssessments));