import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {SubjectHome, SubjectView} from './SubjectHome';
import { customSuperSetState } from "../../../utils";
import { SubjectEditable } from './SubjectEditable/SubjectEditable';
const style = theme => ({
    root: {
        
    }
})
class _Subject extends Component {
    constructor(props) {
        super(props);
        this.state = {
            page : "view", //"home",
            selectedSubject : null
        }
        this.navigateBack = this.navigateBack.bind(this);
    }
    navigateBack = ()=>this.setState({page: "home"});
    mySetState = customSuperSetState(this);
    render() {
        const {classes} = this.props;
        const {page, selectedSubject} = this.state;
        return (
            <div className={classes.root}>
                {page === "home" && 
                    <SubjectHome superSetState={this.mySetState}/>}
                {page === "edit" && 
                    <SubjectEditable goBack={this.navigateBack}/>}
                {page === "view" && 
                    <SubjectView subject={selectedSubject} goBack={this.navigateBack}/>}
            </div>
        );
    }
}
_Subject.propTypes = {
    classes : PropTypes.object.isRequired
};
export const Subjects = withStyles(style)(_Subject);
export {Subjects as default}