import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyPopupMenu } from '../../../../../includes';


const style = theme => ({
    root: {
    }
})
class _TimeTableSubjectSelectHandle extends Component {
    render() {
        const {classes, row, cellMap, selectionHandler, value} = this.props;
        return (
            <div className={classes.root}>
                <MyPopupMenu
                    buttonName={"subject-"+row.sessionSubjectId}
                    buttonValue={value || "Subject"}
                    options={[
                        {name : "None", value : "none"},
                        {name : /* use subject string via provided sessionSubjectId*/ "English", value : 1},                            
                    ]}
                    optionValueProp="value"
                    optionNameProp="name"
                    optionClickCallback={selectionHandler(row, cellMap)}/>
            </div>
        );
    }
}


_TimeTableSubjectSelectHandle.propTypes = {
    classes : PropTypes.object.isRequired,
    subjectId : PropTypes.number,
    row : PropTypes.object,
    cellMap : PropTypes.any,
    selectionHandler : PropTypes.func,
};

const mapStateToProps = state => ({
    state
})


export const TimeTableSubjectSelectHandle = connect(mapStateToProps)(withStyles(style)(_TimeTableSubjectSelectHandle));