import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, mainStageHeaderAction, mainStageHeaderStrings, headerStrings } from '../../../includes';


const style = theme => ({
    root: {
    }
})
class _SubjectEditable extends Component {
    constructor(props){
        super(props);
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "SUBJECTS (EDIT)"
        })(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] :[
                {value : "Back", onClick : ()=>this.props.goBack()}
            ]
        })(dispatch);
    }
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                this is the area for editing 
            </div>
        );
    }
}


_SubjectEditable.propTypes = {
    classes : PropTypes.object.isRequired,
    goBack : PropTypes.func,
};
const mapDispatchToProps = dispatch => {
    return {
        dispatch
    }
}
const mapStateToProps = state => ({
    state
})


export const SubjectEditable = connect(mapStateToProps,mapDispatchToProps)(withStyles(style)(_SubjectEditable));