import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Switch, FormControlLabel } from '@material-ui/core';
import { subjectActions } from '../../../actions';
import { subjectStrings } from '../../../config';
import { colors } from '../../../../../../utils';
import { MyPopupMenu } from '../../../../../includes';


const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "row"
    }
})
class _StudentAndAssessmentsStageHeaderComponent extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedClass : null
        }
    }
    
    setViewUseClassFlter = e => {
        const {dispatch} = this.props;
        subjectActions.setViewUseClassFlter(e.target.checked)(dispatch);
    }
    menuSelectionHandler = option => {
        const{dispatch} = this.props;
        console.log('OPTION ', option);
        this.setState({selectedClass : option});
        //get and set new students 
        subjectActions.getSubjectLevelClassStudents(
            this.levelId, 
            this.classId
        )(dispatch);
    }
    render() {
        const {classes, 
            [subjectStrings.viewUseClassFlter] :viewUseClassFlter,
            [subjectStrings.selectedLevelClasses] : selectedLevelClasses
        } = this.props;
        const {selectedClass } = this.state;
        return (
            <div className={classes.root}>
                <FormControlLabel
                    style={{margin : 10, color : colors.white}}
                    control={<Switch
                        value={Boolean(viewUseClassFlter)}
                        onChange={e=>this.setViewUseClassFlter(e)}
                        />}
                    label="Filter by clases"/>
                {viewUseClassFlter && <MyPopupMenu
                    buttonName="classes"
                    buttonValue={(selectedClass && selectedClass.name) || "Classes"}
                    optionNameProp="name"
                    optionValueProp="_id"
                    optionClickCallback={this.menuSelectionHandler.bind(this)}
                    options={selectedLevelClasses}
                    />}
            </div>
        );
    }
}


_StudentAndAssessmentsStageHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({subjectReducer}) => ({
    [subjectStrings.viewUseClassFlter] : subjectReducer[subjectStrings.viewUseClassFlter],
    [subjectStrings.selectedLevelClasses] : subjectReducer[subjectStrings.selectedLevelClasses],
})


export const StudentAndAssessmentsStageHeaderComponent = 
    connect(mapStateToProps)(withStyles(style)(_StudentAndAssessmentsStageHeaderComponent));