import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {
    TableCell,
    FormControl,
    InputLabel,
    Select,
    MenuItem,
    TextField,
    IconButton,
} from '@material-ui/core';
import {
    RemoveRedEye as RemoveRedEyeIcon,
    Add as AddIcon,
    Delete as DeleteIcon
} from '@material-ui/icons';
import { colors } from '../../../../utils';

const style = theme => ({
    root: {
        
    },
    cell : {
        padding : 5
    }
})
class _CellMapFormat_SubjectHomeView extends Component {
    constructor(props) {
        super(props);
        const {row, cellMap} = props;
        this.state = {
            name : cellMap,
            value : (row[cellMap] && row[cellMap]._id) || ""
        }
        if(props.getMyContext && row.new){
            if(["_id", "action", "level"].indexOf(cellMap) === -1)
                props.getMyContext(this);
        }
        this.inputOnChange = this.inputOnChange.bind(this);
    }
    inputOnChange = e => {
        const value =  e.target.value;
        this.setState({value});
    }
    render() {
        const {
            classes, row, cellMap,            
            levelTeachers,
            levels, 
            terms,
            editMode, 
            teacherSelectHandler,
            selectedLevel,
            addNew,
            deleteSubject
        } = this.props;
        if(row.new){
            const { name, value } = this.state;
            switch(cellMap){
                case "action" : return <TableCell className={classes.cell}>
                    <IconButton onClick={addNew && addNew}>
                        <AddIcon size={30}
                            style={{color : colors.secondary}}/>
                    </IconButton>
                </TableCell>;
                case "name" : return <TableCell className={classes.cell}>
                    <TextField
                        margin="normal"
                        onChange={this.inputOnChange}
                        value={value}
                        />
                </TableCell>;
                case "term" : return <TableCell>
                    <FormControl>
                        {/* <InputLabel htmlFor="teacher">Term</InputLabel> */}
                        <Select
                            onChange={this.inputOnChange}
                            value={value}
                            inputProps={{
                                id : "term"
                            }}>
                                {terms && terms.map((item, index)=>
                                    <MenuItem key={index} value={item._id}>{item.name}</MenuItem>)}
                            </Select>
                    </FormControl>
                </TableCell>;
                case "level" : 
                    if(!levels) return <TableCell className={this.props.classes.cell}></TableCell>;
                    const fetch = 
                    levels.getFirstObjectByPropValue(
                        "_id", selectedLevel._id
                    ); 
                    return <TableCell className={this.props.classes.cell}>
                        {fetch && fetch.item && fetch.item.name}
                    </TableCell>;
                case "teacher" : 
                    return <TableCell className={classes.cell}>{
                        editMode ?  <FormControl>
                            <InputLabel htmlFor="teacher">Teachers</InputLabel>
                            <Select
                                onChange={this.inputOnChange}
                                value={value}
                                inputProps={{
                                    id : "teacher",
                                    
                                }}>
                                    {levelTeachers && levelTeachers.map((item, index)=>
                                        <MenuItem key={index} value={item._id}>{item.fullName}</MenuItem>)}
                                </Select>
                        </FormControl>:
                        (row[cellMap] && row[cellMap].fullName)
                    }</TableCell>;
                default : return <TableCell>

                </TableCell>
            }
        }else {
            switch(cellMap){
                case "action" :    
                    return <TableCell className={this.props.classes.cell}>
                        {editMode ? 
                            <DeleteIcon size={30} color="secondary"
                                onClick={deleteSubject(row)}/>:
                            <RemoveRedEyeIcon 
                            onClick={()=>this.props.superSetState({
                                page : "view", selectedSubject : row
                            })} 
                            style={{color : colors.gray}}/>}
                    </TableCell>
                case "teacher" : 
                    return <TableCell className={this.props.classes.cell}>{
                        editMode ?  <FormControl>
                            <InputLabel htmlFor="teacher">Teachers</InputLabel>
                            <Select
                                onChange={teacherSelectHandler(row)}
                                value={(row[cellMap] && row[cellMap]._id) || ""}
                                inputProps={{
                                    id : "teacher",
                                    
                                }}>
                                    {levelTeachers && levelTeachers.map((item, index)=>
                                        <MenuItem key={index} value={item._id}>{item.fullName}</MenuItem>)}
                                </Select>
                        </FormControl>:
                        (row[cellMap] && row[cellMap].fullName)
                    }</TableCell>;
                case "level" : 
                    if(!levels) return <TableCell className={this.props.classes.cell}></TableCell>;
                    const fetch = 
                    levels.getFirstObjectByPropValue(
                        "_id", row.levelId
                    ); 
                return <TableCell className={this.props.classes.cell}>
                    {fetch && fetch.item && fetch.item.name}
                </TableCell>;
                case "term" : return <TableCell className={this.props.classes.cell}>{
                    row[cellMap] && row[cellMap].name
                }</TableCell>;
                default : return <TableCell className={this.props.classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
}
_CellMapFormat_SubjectHomeView.propTypes = {
    classes : PropTypes.object.isRequired,
    getMyContext : PropTypes.func,
    addNew : PropTypes.func,
    superSetState : PropTypes.func,
};
export const CellMapFormat_SubjectHomeView = withStyles(style)(_CellMapFormat_SubjectHomeView);