import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormControl, Button } from '@material-ui/core';
import { colors } from '../../../../../../utils';
import { subjectStrings } from '../../../config';
import { subjectActions } from '../../../actions';


const style = theme => ({
    root: {
    }
})
class _TimeTableHeaderComponent extends Component {
    setTimeTableEditMode(){
        const {
            [subjectStrings.timeTableEditMode] : timeTableEditMode,
            dispatch
        } = this.props;
        subjectActions.setTimeTableEditeMode(!Boolean(timeTableEditMode))(dispatch);
        /**
         * TO DO
         */
    }
    render() {
        const {
            classes,
            [subjectStrings.timeTableEditMode] : timeTableEditMode
        } = this.props;
        return (
            <div className={classes.root}>
                <FormControl style={{margin : 10}}>
                    <Button 
                        variant="contained" style={{backgroundColor:colors.secondary}}
                        onClick={this.setTimeTableEditMode.bind(this)}>
                            {timeTableEditMode ? "Save" : "Edit"}
                        </Button>
                </FormControl>
            </div>
        );
    }
}


_TimeTableHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({subjectReducer}) => ({
    [subjectStrings.timeTableEditMode] : subjectReducer[subjectStrings.timeTableEditMode]
})


export const TimeTableHeaderComponent = connect(mapStateToProps)(withStyles(style)(_TimeTableHeaderComponent));