import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs } from '../../../../includes';
import { StudentAndAssessments } from './StudentAndAssessments';
import { SubjectTimeTable } from './SubjectTimeTable/SubjectTimeTable';


const style = theme => ({
    root: {
    }
})
class _SubjectView extends Component {
    state = {
        tabValue : null
    }
    render() {
        const {classes, ...props} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{tt : "Time Table", students : "Students/Assessments", }}
                    getInitialTabValue={tabValue => this.setState({tabValue})}
                    />
                <div>
                    {tabValue === "students" && <StudentAndAssessments goBack={this.props.goBack} {...props}/>}
                    {tabValue === "tt" && <SubjectTimeTable goBack={this.props.goBack} {...props}/>}
                </div>
            </div>
        );
    }
}


_SubjectView.propTypes = {
    classes : PropTypes.object.isRequired,
    goBack : PropTypes.func,
};

const mapStateToProps = state => ({
    state
})


export const SubjectView = connect(mapStateToProps)(withStyles(style)(_SubjectView));