import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerStrings, headerActions, breadCrumbActions, mainStageHeaderAction, 
    mainStageHeaderStrings, MyTable, HighlightedInfo } from '../../../includes';
import { colors, errorNotice } from '../../../../utils';
import { SubjectMainStageComponent } from './SubjectMainStageComponent';
import { subjectStrings } from '../config';
import { subjectActions } from '../actions';
import { sessionStrings, sessionActions } from '../../Sessions';
import { teacherStrings } from '../../Teachers';
import { CellMapFormat_SubjectHomeView } from './CellMapFormat_SubjectHomeView';
import { appActions, alertAction } from '../../../../actions';
import { Button } from '@material-ui/core';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
        marginTop : 20
    },
})
class _Subjects extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        this.state = {
            lastId : null,
            rows : 20,
            subjects : null,
            editMode : false
        }
        headerActions({
            [headerStrings.headerTitle] : "SUBJECTS",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Subjects", path : routeNamesSchool.subjects}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.searchActions] : ()=>{},
            [mainStageHeaderStrings.components] :[
                SubjectMainStageComponent
            ],
        })(dispatch);
    }
    
    componentDidMount() {
        const {
            dispatch,
            [sessionStrings.levels] : levels,
        } = this.props;
        const {lastId, rows} = this.state;
        subjectActions.getAllSubjects(lastId, rows, (done, result)=>{
            if(done){
                if(result && result.length !== 0){
                    subjectActions.setSubjectCount(result.length)(dispatch);
                }
            }
        })(dispatch);
        if(!levels) 
            sessionActions.getCurrentSessionLevel()(dispatch);
    }
    inputContext = [];
    getNewInputContext = context => this.inputContext.push(context);
    addNewSubject = () => {
        const {dispatch} = this.props;
        let data = {};
        for (let i = 0; i < this.inputContext.length; i++) {
            const context = this.inputContext[i];
            const {name, value} = context.state;
            if(String(value).trim() === ""){
                return errorNotice(
                    "Missing field(s) in new subject entries",
                    dispatch
                );
            }
            data[name] = value;
        }
        console.log(data);
    }
    deleteSubject = row => {
        console.log(row);
        //check if it is used first before deleting
    }
    deleteSubjectComfirmation = row => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure you want to delete this subject",
            <Button key="delete" 
                style={{color : colors.white}}
                onClick={()=>{
                    this.deleteSubject(row);
                    appActions.closeSnackDialog()(dispatch);
                }}>Continue</Button>
        )(dispatch);
    }
    teacherSelectHandler = rows => e => {
        const value = e.target.value;
        const {
            [teacherStrings.levelTeachers] : levelTeachers,
            [subjectStrings.subjects] : subjects,
            dispatch
        }= this.props;
        if(subjects){
            const {index : subjIndex} = subjects.getFirstObjectByPropValue(
                "_id", rows._id
            ) || {};
            if(levelTeachers && subjIndex){
                const {item} = 
                    levelTeachers.getFirstObjectByPropValue("_id", value);
                subjects[subjIndex].teacher = item;
            }
            subjectActions.setSubjects([...subjects])(dispatch);
        }
    }
    cellFormat = superProps =>  props => 
        <CellMapFormat_SubjectHomeView 
            {...superProps} 
            {...props}/>
    render() {
        let {
            classes,
            [sessionStrings.levels] : levels,
            [subjectStrings.selectedLevel] : selectedLevel,
            [sessionStrings.terms] : terms,
            [subjectStrings.subjedTeacherEditMode] :subjedTeacherEditMode,
            [subjectStrings.subjects] : subjects,
            [teacherStrings.levelTeachers] : levelTeachers,
            superSetState
        } = this.props;
        if(subjedTeacherEditMode) subjects = [...subjects, {new : true}];
        return (
            <div className={classes.root}>
                <HighlightedInfo>To add new subject, filter to school level first, use the filter switch above and select a level to add the subject to and click on the edit button.</HighlightedInfo>
                <MyTable
                    header={["ID", "Name", "Level", "Term", "Ass. Teacher", "Actions"]}
                    dataMap={["_id", "name", "level", "term", "teacher", "action"]}
                    CellMap={this.cellFormat({
                        getMyContext : this.getNewInputContext.bind(this),
                        addNew : this.addNewSubject.bind(this),
                        deleteSubject : this.deleteSubjectComfirmation.bind(this),
                        teacherSelectHandler : this.teacherSelectHandler.bind(this),
                        superSetState,
                        selectedLevel,
                        terms,
                        levels, 
                        levelTeachers,
                        editMode : subjedTeacherEditMode, 
                    })}
                    data={subjects || []}/>
            </div>
        );
    }
}


_Subjects.propTypes = {
    classes : PropTypes.object.isRequired,
    superSetState : PropTypes.func,
};
const mapStateToProps = ({subjectReducer, sessionReducer, teacherReducer}) => ({
    [subjectStrings.subjectFilter] : subjectReducer[subjectStrings.subjectFilter],
    [subjectStrings.selectedLevel] : subjectReducer[subjectStrings.selectedLevel],
    [subjectStrings.selectedTerm] : subjectReducer[subjectStrings.selectedTerm],
    [subjectStrings.usePreviousSubjects] : subjectReducer[subjectStrings.usePreviousSubjects],
    [subjectStrings.subjedTeacherEditMode] : subjectReducer[subjectStrings.subjedTeacherEditMode],
    [subjectStrings.subjects] : subjectReducer[subjectStrings.subjects],
    [sessionStrings.levels] : sessionReducer[sessionStrings.levels],
    [sessionStrings.terms] : sessionReducer[sessionStrings.terms],
    [teacherStrings.levelTeachers] : teacherReducer[teacherStrings.levelTeachers],
})


export const SubjectHome = connect(mapStateToProps)(withStyles(style)(_Subjects));
export {SubjectHome as default};