import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, mainStageHeaderAction, mainStageHeaderStrings, breadCrumbActions, MyTable } from '../../../../../includes';
import { days } from '../../../../../../utils';
import { TableCell } from '@material-ui/core';
import { TimeTableSubjectSelectHandle } from './TimeTableSubjectSelectHandle';
import { TimeTableHeaderComponent } from './TimeTableHeaderComponent';
import { subjectStrings } from '../../../config';
import { SchoolDay } from './SchoolDay';
import { subjectActions } from '../../../actions';
import { routeNamesSchool } from '../../../../routeNames';

const levelTable = [
    {
        classId : 1,
        class : {
            name : "Primary 1 B",
        },
        timeTable : [
            {
                _id : 1,
                day : "Mondays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
            {
                _id : 1,
                day : "Tuesdays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
        ]
    },
    {
        classId : 2,
        class : {
            name : "Primary 1 C",
        },
        timeTable : [
            {
                _id : 1,
                day : "Mondays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
            {
                _id : 1,
                day : "Tuesdays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
        ]
    },
]
const style = theme => ({
    root: {
        marginTop : 30
    }
})
class _SubjectTimeTable extends Component {
    constructor(props) {
        super(props);
        this.state = {
            levelTable,
            schoolDay : "Monday"
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "SUBJECTS (TIME TABLE)"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Subjects", path : routeNamesSchool.subjects},
            {name : "Time Table", path : ""}
        ])(dispatch)
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {value : "Back", onClick : this.props.goBack}
            ],
            [mainStageHeaderStrings.components] : [
                TimeTableHeaderComponent
            ]
        })(dispatch);
        this.subjectId = props.subjectId || 1;

        this.setSchoolDay = this.setSchoolDay.bind(this);
        this.initializeComponents();
    }
    initializeComponents(){
        const {
            dispatch, 
            [subjectStrings.selectedLevel] : selectedLevel,
            [subjectStrings.selectedTerm] : selectedTerm
        } = this.props;
        /**
         * TO DO    
         *  get the selected level and term id
         */
        subjectActions.getTimeTableDurationFormat(1, 1)(dispatch);
    }
    generateTableHeader = timeFormat => {
        let header = ["Classes"];
        let dataMap = ["class"];
        if(timeFormat) for (let i = 0; i < timeFormat.length; i++) {
            const time = timeFormat[i];
            header.push(time.start+"-"+time.end);
            dataMap.push(time._id);
        }
        return {header, dataMap};
    }
    generateData = (levelTable, day="Monday") => {
        let data = [];
        if(levelTable) for (let i = 0; i < levelTable.length; i++) {
            const timeTableInfo = levelTable[i];
            const {timeTable, classId, class : classInfo} = timeTableInfo;
            let dataInfo = { classId, class : classInfo.name };
            for (let j = 0; j < timeTable.length; j++) {
                const timeInfo = timeTable[j];
                const {day : classDay, time} = timeInfo;
                if(day === classDay && time){
                    for (let k = 0; k < time.length; k++) {
                        const schedule = time[k];
                        // dataInfo.sessionSubjectId = schedule.sessionSubjectId;
                        dataInfo[schedule.formatId] = schedule.sessionSubjectId; //"English"; //get the subject infos
                    }
                }
            }
            data.push(dataInfo);
        }
        return data;
    }
    getSubjectNames(subjectId){
        const subjects = {
            1 : "English",
            2 : "Maths",
            "none" : "None"
        }
        return subjects[subjectId];
    }
    cellMapFormat = (subjectId, editMode) => ({row, cellMap})=>{
        if(editMode && (row[cellMap] === subjectId || !row[cellMap])) 
            return <TableCell>
                <TimeTableSubjectSelectHandle 
                    subjectId={subjectId}
                    row={row} cellMap={cellMap}
                    value={this.getSubjectNames(row[cellMap])}
                    selectionHandler={this.setTimeTableSubject.bind(this)}/>
            </TableCell>        
        else if(cellMap === "class") return <TableCell>
                {row[cellMap]}
            </TableCell> 
        else return <TableCell>
                {this.getSubjectNames(row[cellMap])}
            </TableCell>
        
    }
    setTimeTableSubject = (row, formatId) => subjectOption => {
        let {levelTable, schoolDay} = this.state;
        let {item, index} = levelTable.getFirstObjectByPropValue("classId", row.classId);
        if(item){
            let {classId, timeTable} = item;
            if(classId === row.classId){ //just incase i decide to combine all classes, this will sieve
                if(subjectOption.value !== "none"){
                    if(timeTable){
                        const timeTableItem = timeTable.getFirstObjectByPropValue("day", schoolDay);
                        if(timeTableItem){
                            let {item : tableItem, index : tableIndex} = timeTableItem;
                            if(tableItem){
                                let {time} = tableItem;
                                if(time) {
                                    let {item : timeItem, index : timeIndex} = time.getFirstObjectByPropValue("formatId", formatId) || {};
                                    if(timeItem){
                                        timeItem = {...timeItem, sessionSubjectId : subjectOption.value};
                                        time[timeIndex] = timeItem;
                                    }else{
                                        time.push({formatId, sessionSubjectId : subjectOption.value});
                                    }
                                }else {
                                    time = [{formatId, sessionSubjectId : subjectOption.value}];
                                }
                                tableItem.time = [...time];
                                timeTable[tableIndex] = tableItem;
                            }else {
                                tableItem = {
                                    day : schoolDay,
                                    time : [{formatId, sessionSubjectId : subjectOption.value}]
                                }
                                timeTable.push(tableItem);
                            }
                        }else{
                            timeTable.push({
                                day : schoolDay,
                                time : [{formatId, sessionSubjectId : subjectOption.value}]
                            });
                        }
                    }else {
                        timeTable = [{
                            day : schoolDay,
                            time : [{formatId, sessionSubjectId : subjectOption.value}]
                        }]
                    }
                    item = {...item, timeTable};
                    levelTable[index] = item;
                    levelTable = [...levelTable];
                    this.setState({levelTable});
                    return;
                }else{
                    if(timeTable){
                        let {item : tableItem, index : tableIndex} = timeTable.getFirstObjectByPropValue("day", schoolDay);
                        if(tableItem){
                            let {time} = tableItem;
                            if(time) {
                                let {item : timeItem, index : timeIndex} = time.getFirstObjectByPropValue("formatId", formatId) || {};
                                if(timeItem)
                                    time.splice(timeIndex, 1);                                
                            }
                            tableItem.time = [...time];
                            timeTable[tableIndex] = tableItem;
                        }
                    }
                    item = {...item, timeTable};
                    levelTable[index] = item;
                    levelTable = [...levelTable];
                    this.setState({levelTable});
                    return;
                }
            }
        }
    }
    
    setSchoolDay = dayIndex => this.setState({schoolDay : days[dayIndex]});
    render() {
        const {
            classes,
            [subjectStrings.timeTableEditMode] : timeTableEditMode,
            [subjectStrings.timeTableDurationFormat] : timeTableFormat
        } = this.props;
        const {levelTable, schoolDay} = this.state;
        /**
         *  the header is derived within the generate and the table header (time)
         *  id form part of the data... check the muiltheader of the mytable
         */
        return (
            <div className={classes.root}>
                {timeTableFormat && <div>
                    <SchoolDay
                        days={days}
                        getInitialDayIndex={this.setSchoolDay}
                        setSuperDayIndex={this.setSchoolDay}/>
                    <MyTable
                        {...this.generateTableHeader(timeTableFormat)}
                        data={this.generateData(levelTable, schoolDay)}
                        CellMap={this.cellMapFormat(this.subjectId, timeTableEditMode)}
                        />
                    </div>}
            </div>
        );
    }
}


_SubjectTimeTable.propTypes = {
    classes : PropTypes.object.isRequired,
    goBack : PropTypes.func,
};

const mapStateToProps = ({subjectReducer}) => ({
    [subjectStrings.selectedLevel] : subjectReducer[subjectStrings.selectedLevel],
    [subjectStrings.selectedTerm] : subjectReducer[subjectStrings.selectedTerm],
    [subjectStrings.timeTableEditMode] : subjectReducer[subjectStrings.timeTableEditMode],
    [subjectStrings.timeTableDurationFormat] : subjectReducer[subjectStrings.timeTableDurationFormat],
})


export const SubjectTimeTable = connect(mapStateToProps)(withStyles(style)(_SubjectTimeTable));