import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormGroup, IconButton, FormLabel } from '@material-ui/core';
import { ArrowBackIos, ArrowForwardIos } from '@material-ui/icons';
import { colors } from '../../../../../../utils';


const style = theme => ({
    root: {
        display : "flex",
        justifyContent : "center",
    }
})
class _SchoolDay extends Component {
    constructor(props) {
        super(props);
        this.state = {
            dayIndex : 0,
            startLimit : true,
            endLimit : false,
        }
        if(props.getInitialDayIndex)
            props.getInitialDayIndex(this.state.dayIndex);
    }
    handleClick = forward => () =>{
        let {dayIndex, startLimit, endLimit} = this.state;
        if(forward){
            dayIndex++;
            if(startLimit) 
                this.setState({startLimit : false})
            if(dayIndex === this.props.days.length - 1)
                this.setState({endLimit: true});
        }else{
            dayIndex--;
            if(endLimit)
                this.setState({endLimit: false});
            if(dayIndex === 0)
                this.setState({startLimit: true});
        }
        this.setState({dayIndex});
        this.props.setSuperDayIndex(dayIndex);
    }
    render() {
        const {classes, days} = this.props;
        const {dayIndex, startLimit, endLimit} = this.state;
        return (
            <div className={classes.root}>
                <FormGroup style={{
                    flexDirection : "row"
                }}>
                    <IconButton
                        disabled={startLimit}
                        onClick={this.handleClick()}>
                        <ArrowBackIos 
                            style={{color : !startLimit && colors.secondary}} 
                            fontSize="large"/>
                    </IconButton>
                    <FormLabel style={{
                        display : "flex", 
                        flexGrow:1, 
                        alignItems : "center",
                        color : colors.secondary,
                        fontWeight : "bold"
                    }}>{days && days[dayIndex]}</FormLabel>
                    <IconButton 
                        disabled={endLimit}
                        onClick={this.handleClick(true)}>
                        <ArrowForwardIos
                            style={{color : !endLimit && colors.secondary}} 
                            fontSize="large"/>
                    </IconButton>
                </FormGroup>
            </div>
        );
    }
}


_SchoolDay.propTypes = {
    classes : PropTypes.object.isRequired,
    days : PropTypes.array,
    getInitialDayIndex : PropTypes.func,
    setSuperDayIndex : PropTypes.func,
};

const mapStateToProps = state => ({
    state
})


export const SchoolDay = connect(mapStateToProps)(withStyles(style)(_SchoolDay));